class Solution {
public:
    string largestPalindrome(int n, int k) {
        if (n == 1) {
            for (int i = 9; i > 0; --i) {
                if (i % k == 0) return to_string(i);
            }
        }
        string res;
        for (int i = 9; i >= 0; --i) {
            string s = to_string(i);
            for (int j = 9; j >= 0; --j) {
                string mid = to_string(j);
                string t = s + mid + string(s.rbegin(), s.rend());
                if (t.length() == n && stoi(t) % k == 0) {
                    if (res.empty() || t > res) res = t;
                }
            }
        }
        return res;
    }
};

